SELECT  LISTAGG(V_PLAN_PRESUPUESTAL.NOMBRE,'-')WITHIN GROUP(ORDER BY V_PLAN_PRESUPUESTAL.ID)AS NOM_RUBROS, LISTAGG(BP_PROYECTOSRUBROS.RUBROPPTALES,'-')WITHIN GROUP(ORDER BY RUBROPPTALES)AS RUBROS, TO_CHAR(BP_PROYFUENTESFINANCIACION.VALOR, '99G999G999G999', 'NLS_NUMERIC_CHARACTERS = ".,"') AS VALOR_APORTE, FUENTE_RECURSOS.NOMBRE NOMBRE_FUENTE FROM  BP_PROYECTOSRUBROS INNER JOIN V_PLAN_PRESUPUESTAL ON  V_PLAN_PRESUPUESTAL.COMPANIA=BP_PROYECTOSRUBROS.COMPANIA AND BP_PROYECTOSRUBROS.VIGENCIA = V_PLAN_PRESUPUESTAL.ANO AND BP_PROYECTOSRUBROS.RUBROPPTALES = V_PLAN_PRESUPUESTAL.ID LEFT  JOIN BP_PROYFUENTESFINANCIACION ON BP_PROYFUENTESFINANCIACION.COMPANIA =BP_PROYECTOSRUBROS.COMPANIA AND BP_PROYFUENTESFINANCIACION.PROYECTO=BP_PROYECTOSRUBROS.PROYECTO INNER JOIN FUENTE_RECURSOS ON BP_PROYECTOSRUBROS.COMPANIA = FUENTE_RECURSOS.COMPANIA AND BP_PROYECTOSRUBROS.FUENTERECURSOSRUBRO = FUENTE_RECURSOS.CODIGO AND BP_PROYECTOSRUBROS.VIGENCIA=FUENTE_RECURSOS.ANO WHERE BP_PROYECTOSRUBROS.COMPANIA =s$compania$s AND BP_PROYECTOSRUBROS.PROYECTO ='s$codigo$s'AND BP_PROYECTOSRUBROS.RUBROPPTALES = V_PLAN_PRESUPUESTAL.ID GROUP BY  BP_PROYECTOSRUBROS.COMPANIA, BP_PROYECTOSRUBROS.FUENTERECURSOSRUBRO, BP_PROYFUENTESFINANCIACION.VALOR, BP_PROYFUENTESFINANCIACION.CODIGOFUENTE, FUENTE_RECURSOS.NOMBRE